async function loadConfig(){if(!api)return;const c=await api.getConfig();lastfmUser.value=c.lastfmUser;lastfmApiKey.value=c.lastfmApiKey;spotifyClientId.value=c.spotifyClientId;googleClientId.value=c.googleClientId;googleClientSecret.value=c.googleClientSecret;setConnected('Last.fm',!!(c.lastfmUser&&c.lastfmApiKey));setConnected('Spotify',c.spotifyConnected);setConnected('YouTube',c.youtubeConnected);if(c.lastfmUser&&c.lastfmApiKey)await loadRealRecommendations();}
function setConnected(service,on){const btn=[...document.querySelectorAll('.connect')].find(b=>b.dataset.service===service);btn.classList.toggle('connected',on);btn.querySelector('small').textContent=on?'Conectado':'Conectar';btn.querySelector('b').textContent=on?'✓':'+';}
async function loadRealRecommendations(){try{
  const top=await api.lastfm('user.getTopArtists',{period:'3month',limit:'8'});
  const lastfmSeeds=top.topartists.artist.slice(0,4);
  let spotifySeeds=[];
  try{const spotifyTop=await api.spotify('/me/top/artists?time_range=medium_term&limit=8');spotifySeeds=spotifyTop.items||[];}catch{}
  const seedNames=[...lastfmSeeds.map(a=>a.name),...spotifySeeds.map(a=>a.name)].filter((n,i,all)=>all.findIndex(x=>x.toLowerCase()===n.toLowerCase())===i).slice(0,6);
  const results=await Promise.all(seedNames.slice(0,4).map(name=>api.lastfm('artist.getSimilar',{artist:name,limit:'8',autocorrect:'1'})));
  const known=new Set(seedNames.map(name=>name.toLowerCase()));
  const found=results.flatMap(r=>r.similarartists?.artist||[]).filter(a=>!known.has(a.name.toLowerCase())).filter((a,i,all)=>all.findIndex(x=>x.name.toLowerCase()===a.name.toLowerCase())===i).slice(0,6);
  if(found.length){artists.splice(0,artists.length,...found.map((a,i)=>{const seed=seedNames[i%seedNames.length];const inSpotify=spotifySeeds.some(s=>s.name.toLowerCase()===seed.toLowerCase());return{name:a.name,genre:`similar a ${seed}`,mood:['Todo',i%2?'Noche':'Calma',i%3?'Energía':'Calma'],match:Math.max(78,96-i*3),why:`${inSpotify?'Spotify y Last.fm':'Last.fm'} lo conecta con ${seed}, parte central de tus escuchas.`,tone:['#7a665c','#46525a','#746955','#674d51','#556158','#4e535e'][i],orb:['radial-gradient(circle,#e0b9a7,#43383c 60%)','conic-gradient(#d9ff43,#7699a5,#20292d)','radial-gradient(circle,#efca77,#4a453d 60%)'][i%3]}}));render();notify(`Radar actualizado con Last.fm${spotifySeeds.length?' + Spotify':''}`);}
}catch(e){notify(e.message)} }
document.querySelectorAll('.connect').forEach(btn=>btn.addEventListener('click',async()=>{if(!api){notify('Abre la versión de escritorio para conectar cuentas');return;}if(btn.dataset.service==='Spotify'){try{notify('Abriendo autorización de Spotify…');await api.connectSpotify();setConnected('Spotify',true);notify('Spotify quedó vinculado');await loadRealRecommendations();}catch(e){notify(e.message)}}else if(btn.dataset.service==='YouTube'){try{const c=await api.getConfig();if(!c.googleClientId||!c.googleClientSecret){dialog.showModal();notify('Guarda el Client ID y Client secret de Google');return;}notify('Abriendo autorización de Google…');await api.connectYouTube();setConnected('YouTube',true);notify('YouTube quedó vinculado');}catch(e){notify(e.message)}}else dialog.showModal();}));
document.querySelector('#settingsBtn').addEventListener('click',async()=>{if(!api){notify('La configuración está disponible en la app instalada');return;}const c=await api.getConfig();lastfmUser.value=c.lastfmUser;lastfmApiKey.value=c.lastfmApiKey;spotifyClientId.value=c.spotifyClientId;googleClientId.value=c.googleClientId;googleClientSecret.value=c.googleClientSecret;dialog.showModal();});
document.querySelector('#settingsForm').addEventListener('submit',async e=>{if(e.submitter?.value==='cancel')return;e.preventDefault();await api.saveConfig({lastfmUser:lastfmUser.value.trim(),lastfmApiKey:lastfmApiKey.value.trim(),spotifyClientId:spotifyClientId.value.trim(),googleClientId:googleClientId.value.trim(),googleClientSecret:googleClientSecret.value.trim()});dialog.close();setConnected('Last.fm',!!(lastfmUser.value&&lastfmApiKey.value));notify('Configuración guardada en este equipo');await loadRealRecommendations();});
