function openView(view,button){document.querySelectorAll('.nav-link').forEach(n=>n.classList.remove('active'));if(button)button.classList.add('active');discoverSections.forEach(s=>s.hidden=view!=='discover');neighborsView.hidden=view!=='neighbors';compareView.hidden=true;compareV1View.hidden=view!=='compare-v1';maxicoverView.hidden=view!=='maxicover';libraryView.hidden=view!=='library';songsView.hidden=view!=='songs';labsView.hidden=view!=='labs';if(view==='neighbors')loadNeighbors();if(view==='compare-v1')loadCompareV1Playlists();if(view==='library')loadInternalPlaylists();if(view==='songs')loadSongs();}
