document.querySelector('#sidebarCollapse').addEventListener('click',()=>{appSidebar.classList.toggle('collapsed');localStorage.setItem('recomendapp-sidebar-collapsed',appSidebar.classList.contains('collapsed')?'1':'0')});if(localStorage.getItem('recomendapp-sidebar-collapsed')==='1')appSidebar.classList.add('collapsed');
document.querySelector('#sidebarSettings').addEventListener('click',()=>document.querySelector('#settingsBtn').click());document.querySelector('#labsView').addEventListener('click',event=>{const lab=event.target.closest('[data-lab]');if(lab)openView(lab.dataset.lab);});
const getImage=images=>(images||[]).slice().reverse().find(i=>i['#text'])?.['#text']||'';
const escapeHtml=value=>String(value||'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const spotifyId=url=>{try{const u=new URL(url);const parts=u.pathname.split('/').filter(Boolean);return parts[0]==='user'&&parts[1]?parts[1]:''}catch{return ''}};
async function neighborDetails(name,match=''){const [info,top,recent]=await Promise.all([api.lastfm('user.getInfo',{user:name}),api.lastfm('user.getTopArtists',{user:name,period:'3month',limit:'4'}),api.lastfm('user.getRecentTracks',{user:name,limit:'1'})]);const user=info.user;const track=recent.recenttracks?.track?.[0];return{name:user.name,realname:user.realname,country:user.country,playcount:user.playcount,url:user.url,image:getImage(user.image),match,artists:(top.topartists?.artist||[]).map(a=>a.name),now:track?`${track.artist?.['#text']||track.artist?.name} — ${track.name}`:'Sin escucha reciente'};}
async function playlistsFor(name){const url=neighborStore[name]?.spotify||'';const id=spotifyId(url);if(!id)return[];try{const data=await api.spotify(`/users/${encodeURIComponent(id)}/playlists?limit=8`);return(data.items||[]).filter(Boolean).map(p=>({name:p.name,url:p.external_urls?.spotify}));}catch{return[]}}
async function renderNeighborCard(person){const playlists=await playlistsFor(person.name);const initials=person.name.slice(0,2).toUpperCase();const limit=neighborStore[person.name]?.limit??250;return `<article class="neighbor-card" data-neighbor="${escapeHtml(person.name)}"><button class="remove-neighbor" title="Quitar">×</button>${person.image?`<img class="neighbor-avatar" src="${escapeHtml(person.image)}" alt="">`:`<div class="neighbor-avatar">${initials}</div>`}<div class="neighbor-main"><h3>${escapeHtml(person.realname||person.name)}</h3><div class="neighbor-meta">@${escapeHtml(person.name)} · ${escapeHtml(person.country||'mundo')} · ${Number(person.playcount||0).toLocaleString()} scrobbles ${person.match?`· <span class="compatibility">${escapeHtml(person.match)} afinidad</span>`:''}</div><div class="neighbor-now">Escuchando: ${escapeHtml(person.now)}</div><div class="neighbor-artists">${person.artists.map(a=>`<span>${escapeHtml(a)}</span>`).join('')}</div><div class="neighbor-links"><a href="${escapeHtml(person.url)}" target="_blank">Last.fm ↗</a>${neighborStore[person.name]?.spotify?`<a href="${escapeHtml(neighborStore[person.name].spotify)}" target="_blank">Spotify ↗</a>`:`<button class="link-spotify">Vincular Spotify</button>`}<label class="neighbor-limit">Límite <input class="neighbor-limit-input" type="number" min="0" step="1" value="${limit}" title="0 significa sin límite"></label></div></div><div class="neighbor-playlists"><strong>PLAYLISTS PÚBLICAS</strong><div class="playlist-row">${playlists.length?playlists.map(p=>`<a class="playlist-chip" href="${escapeHtml(p.url)}" target="_blank">${escapeHtml(p.name)} ↗</a>`).join(''):'<span class="neighbor-meta">Vincula su perfil para verlas</span>'}</div></div></article>`;}
async function loadNeighbors(){if(!api){neighborsStatus.textContent='Instala la app para cargar tus vecinos.';return;}neighborsStatus.textContent='Buscando tus vecinos musicales…';let candidates=[];try{const result=await api.lastfm('user.getNeighbours',{limit:'12'});candidates=(result.neighbours?.user||[]).map(u=>({name:u.name,match:u.match||''}));}catch{}const manual=Object.entries(neighborStore).map(([name,v])=>({name,match:v.match||''}));candidates=[...candidates,...manual].filter((v,i,a)=>a.findIndex(x=>x.name.toLowerCase()===v.name.toLowerCase())===i).slice(0,12);currentNeighborNames=candidates.map(c=>c.name);if(!candidates.length){neighborsStatus.innerHTML='Last.fm no expuso la lista automática para esta cuenta. Añade un vecino con su usuario de Last.fm.';neighborsGrid.innerHTML='';return;}const details=(await Promise.all(candidates.map(c=>neighborDetails(c.name,c.match).catch(()=>null)))).filter(Boolean);neighborsStatus.textContent=`${details.length} vecinos encontrados`;neighborsGrid.innerHTML=(await Promise.all(details.map(renderNeighborCard))).join('');}
document.querySelector('#addNeighborBtn').addEventListener('click',()=>{neighborLastfm.value='';neighborSpotify.value='';neighborLimit.value='250';neighborDialog.showModal()});
document.querySelector('#neighborForm').addEventListener('submit',e=>{if(e.submitter?.value==='cancel')return;e.preventDefault();const name=neighborLastfm.value.trim();if(!name)return;neighborStore[name]={spotify:neighborSpotify.value.trim(),limit:Math.max(0,Number(neighborLimit.value)||0)};localStorage.setItem('recomendapp-neighbors',JSON.stringify(neighborStore));neighborDialog.close();loadNeighbors();});
document.querySelector('#neighborsGrid').addEventListener('click',e=>{const card=e.target.closest('.neighbor-card');if(!card)return;const name=card.dataset.neighbor;if(e.target.closest('.remove-neighbor')){delete neighborStore[name];localStorage.setItem('recomendapp-neighbors',JSON.stringify(neighborStore));loadNeighbors();}if(e.target.closest('.link-spotify')){const link=prompt(`Pega el enlace del perfil de Spotify de ${name}:`,'https://open.spotify.com/user/');if(link&&spotifyId(link)){neighborStore[name]={limit:250,...(neighborStore[name]||{}),spotify:link.trim()};localStorage.setItem('recomendapp-neighbors',JSON.stringify(neighborStore));loadNeighbors();}else if(link)notify('Ese enlace de Spotify no es válido');}if(e.target.closest('.limit-neighbor')){const current=neighborStore[name]?.limit??250;const value=prompt(`Máximo de scrobbles para ${name}. Usa 0 para no limitar:`,String(current));if(value!==null&&/^\d+$/.test(value.trim())){neighborStore[name]={...(neighborStore[name]||{}),limit:Number(value)};localStorage.setItem('recomendapp-neighbors',JSON.stringify(neighborStore));loadNeighbors();}else if(value!==null)notify('Introduce un número entero desde 0');}});
document.querySelector('#neighborsGrid').addEventListener('change',e=>{if(!e.target.matches('.neighbor-limit-input'))return;const name=e.target.closest('.neighbor-card').dataset.neighbor;const limit=Math.max(0,Math.floor(Number(e.target.value)||0));e.target.value=limit;neighborStore[name]={...(neighborStore[name]||{}),limit};localStorage.setItem('recomendapp-neighbors',JSON.stringify(neighborStore));notify(`Límite de ${name}: ${limit===0?'sin límite':limit}`);});
async function buildNeighborsPlaylist(){if(!currentNeighborNames.length){notify('Añade al menos un vecino primero');return;}const btn=document.querySelector('#syncPlaylistBtn');btn.disabled=true;btn.textContent='Buscando últimos scrobbles…';try{const feeds=await Promise.all(currentNeighborNames.map(name=>api.lastfm('user.getRecentTracks',{user:name,limit:'5'}).catch(()=>null)));const tracks=feeds.flatMap(f=>f?.recenttracks?.track||[]).map(t=>({name:t.name,artist:t.artist?.['#text']||t.artist?.name})).filter(t=>t.name&&t.artist).filter((t,i,a)=>a.findIndex(x=>`${x.artist}-${x.name}`.toLowerCase()===`${t.artist}-${t.name}`.toLowerCase())===i).slice(0,50);if(!tracks.length)throw new Error('No encontré scrobbles recientes públicos.');btn.textContent=`Buscando ${tracks.length} canciones en Spotify…`;const found=[];for(const track of tracks){const q=encodeURIComponent(`track:${track.name} artist:${track.artist}`);const result=await api.spotify(`/search?q=${q}&type=track&limit=1`);const uri=result.tracks?.items?.[0]?.uri;if(uri&&!found.includes(uri))found.push(uri);}if(!found.length)throw new Error('Spotify no encontró estas canciones.');let playlistId=localStorage.getItem('recomendapp-neighbors-playlist');let playlistUrl=localStorage.getItem('recomendapp-neighbors-playlist-url');if(!playlistId){const created=await api.spotify('/me/playlists',{method:'POST',body:{name:'Neighbors — Recomendapp',public:false,description:'Últimos scrobbles de mis vecinos musicales. Actualizada por Recomendapp.'}});playlistId=created.id;playlistUrl=created.external_urls?.spotify;localStorage.setItem('recomendapp-neighbors-playlist',playlistId);localStorage.setItem('recomendapp-neighbors-playlist-url',playlistUrl||'');}await api.spotify(`/playlists/${playlistId}/items`,{method:'PUT',body:{uris:found.slice(0,100)}});notify(`Playlist actualizada con ${found.length} canciones`);if(playlistUrl)window.open(playlistUrl,'_blank');}catch(e){if(/scope|permission|403/i.test(e.message)){notify('Spotify necesita un permiso nuevo. Autoriza de nuevo…');try{await api.connectSpotify();await buildNeighborsPlaylist();}catch(authError){notify(authError.message)}}else notify(e.message);}finally{btn.disabled=false;btn.textContent='♫ Actualizar playlist';}}
async function allScrobbles(name,from,max,onProgress){if(typeof max==='function'){onProgress=max;max=neighborStore[name]?.limit??250;}let page=1,totalPages=1,tracks=[];do{if(syncCancelled)throw new Error('__SYNC_CANCELLED__');const pageLimit=max>0?Math.min(200,Math.max(1,max-tracks.length)):200;const data=await api.lastfm('user.getRecentTracks',{user:name,from:String(from),limit:String(pageLimit),page:String(page)});const batch=(data.recenttracks?.track||[]).filter(t=>!t['@attr']?.nowplaying);tracks.push(...batch);totalPages=Number(data.recenttracks?.['@attr']?.totalPages||1);const available=Number(data.recenttracks?.['@attr']?.total||tracks.length);if(onProgress)onProgress(name,tracks.length,max>0?Math.min(max,available):available);page++;}while(page<=totalPages&&(max===0||tracks.length<max));return tracks.slice(0,max||undefined).map(t=>({name:t.name,artist:t.artist?.['#text']||t.artist?.name,neighbor:name,uts:Number(t.date?.uts||0)})).filter(t=>t.name&&t.artist);}
async function buildNeighborsPlaylist(){if(!currentNeighborNames.length){notify('Añade al menos un vecino primero');return;}const btn=document.querySelector('#syncPlaylistBtn');btn.disabled=true;btn.textContent='Leyendo scrobbles…';try{const days=Number(neighborPeriod.value);localStorage.setItem('recomendapp-neighbor-period',days);const from=Math.floor((Date.now()-days*86400000)/1000);const tracks=[];for(const name of currentNeighborNames){const userTracks=await allScrobbles(name,from,(user,loaded,total)=>btn.textContent=`${user}: ${loaded}/${total} scrobbles…`).catch(()=>[]);tracks.push(...userTracks);}if(!tracks.length)throw new Error('No encontré scrobbles públicos en ese periodo.');const unique=[...new Map(tracks.map(t=>[`${t.artist}\u0000${t.name}`.toLowerCase(),t])).values()];const uriMap=new Map(JSON.parse(localStorage.getItem('recomendapp-track-uri-cache')||'[]'));let searched=0;for(const track of unique){const key=`${track.artist}\u0000${track.name}`.toLowerCase();if(!uriMap.has(key)){btn.textContent=`Buscando en Spotify ${++searched}/${unique.length}…`;const q=encodeURIComponent(`track:${track.name} artist:${track.artist}`);const result=await api.spotify(`/search?q=${q}&type=track&limit=1`);uriMap.set(key,result.tracks?.items?.[0]?.uri||'');}}localStorage.setItem('recomendapp-track-uri-cache',JSON.stringify([...uriMap]));const found=tracks.map(t=>uriMap.get(`${t.artist}\u0000${t.name}`.toLowerCase())).filter(Boolean);if(!found.length)throw new Error('Spotify no encontró estas canciones.');let playlistId=localStorage.getItem('recomendapp-neighbors-playlist');let playlistUrl=localStorage.getItem('recomendapp-neighbors-playlist-url');if(!playlistId){const created=await api.spotify('/me/playlists',{method:'POST',body:{name:'Neighbors — Recomendapp',public:false,description:'Todos los scrobbles del periodo seleccionado para mis vecinos. Actualizada por Recomendapp.'}});playlistId=created.id;playlistUrl=created.external_urls?.spotify;localStorage.setItem('recomendapp-neighbors-playlist',playlistId);localStorage.setItem('recomendapp-neighbors-playlist-url',playlistUrl||'');}btn.textContent=`Guardando ${found.length} scrobbles…`;await api.spotify(`/playlists/${playlistId}/items`,{method:'PUT',body:{uris:found.slice(0,100)}});for(let i=100;i<found.length;i+=100){btn.textContent=`Guardando ${Math.min(i+100,found.length)}/${found.length}…`;await api.spotify(`/playlists/${playlistId}/items`,{method:'POST',body:{uris:found.slice(i,i+100)}});}const missing=tracks.length-found.length;notify(`Playlist: ${found.length}/${tracks.length} scrobbles${missing?` · ${missing} no encontrados`:''}`);if(playlistUrl)window.open(playlistUrl,'_blank');}catch(e){if(/scope|permission|403/i.test(e.message)){notify('Spotify necesita permisos nuevos. Autoriza de nuevo…');try{await api.connectSpotify();await buildNeighborsPlaylist();}catch(authError){notify(authError.message)}}else notify(e.message);}finally{btn.disabled=false;btn.textContent='♫ Actualizar playlist';}}
async function spotifyUrisFast(tracks,btn){
  const unique=[...new Map(tracks.map(t=>[`${t.artist}\u0000${t.name}`.toLowerCase(),t])).values()];
  const uriMap=new Map(JSON.parse(localStorage.getItem('recomendapp-track-uri-cache')||'[]'));
  const pending=unique.filter(t=>!uriMap.has(`${t.artist}\u0000${t.name}`.toLowerCase()));
  let cursor=0,completed=0,deferred=0,spotifyUnavailable=false;
  const persist=()=>localStorage.setItem('recomendapp-track-uri-cache',JSON.stringify([...uriMap]));
  async function worker(){while(cursor<pending.length&&!spotifyUnavailable){if(syncCancelled)return;const track=pending[cursor++];syncCurrent.textContent=`Buscando: ${track.artist} — ${track.name}`;markSyncProgress(`Consultando el catálogo para ${track.artist} — ${track.name}.`);const key=`${track.artist}\u0000${track.name}`.toLowerCase();const q=encodeURIComponent(`track:${track.name} artist:${track.artist}`);try{spotifySearchCount++;if(document.querySelector('#spotifyQuota'))spotifyQuota.textContent=`Spotify no publica el cupo restante · ${spotifySearchCount} consultas · ${spotifyWaitUntil>Date.now()?`espera hasta ${new Date(spotifyWaitUntil).toLocaleTimeString()}`:'sin espera confirmada'}`;const result=await api.spotify(`/search?q=${q}&type=track&limit=1`,{timeoutMs:8000,timeoutRetries:0,requestGroup:'neighbors-sync'});uriMap.set(key,result.tracks?.items?.[0]?.uri||'');markSyncProgress(`Última coincidencia completada: ${track.artist} — ${track.name}.`);}catch(error){if(error.message.includes('SPOTIFY_CANCELLED'))return;if(error.message.includes('SPOTIFY_RATE_LIMIT')){spotifyUnavailable=true;const seconds=Number(error.message.split(':').pop())||0;syncHint.textContent=`Spotify exige esperar ${seconds}s. Continuando ahora con YouTube.`;return;}if(error.message.includes('SPOTIFY_TIMEOUT')){deferred++;syncHint.textContent=`Sin respuesta para ${track.artist} — ${track.name}. Queda pendiente para la próxima sincronización.`;}else throw error;}completed++;btn.textContent=`Spotify: ${completed}/${pending.length}`;syncStage.textContent='Buscando canciones en Spotify';syncNumbers.textContent=`${completed} / ${pending.length}${deferred?` · ${deferred} pendientes`:''}`;syncBar.style.width=`${pending.length?completed/pending.length*100:100}%`;if(completed%20===0)persist();}}
  if(pending.length)await Promise.all(Array.from({length:Math.min(5,pending.length)},worker));
  persist();
  if(syncCancelled)throw new Error('__SYNC_CANCELLED__');
  return {uris:unique.map(t=>uriMap.get(`${t.artist}\u0000${t.name}`.toLowerCase())).filter(Boolean),missing:unique.filter(t=>!uriMap.get(`${t.artist}\u0000${t.name}`.toLowerCase())),cached:unique.length-pending.length,searched:pending.length,deferred};
}
async function buildNeighborsPlaylistFast(){
  if(!currentNeighborNames.length){notify('Añade al menos un vecino primero');return;}
  const btn=document.querySelector('#syncPlaylistBtn');syncCancelled=false;startSyncHints();cancelSyncBtn.disabled=false;btn.disabled=true;btn.textContent='Leyendo scrobbles…';syncProgress.hidden=false;syncStage.textContent='Leyendo Last.fm';syncNumbers.textContent='';syncBar.style.width='0%';syncCurrent.textContent='Recopilando scrobbles de tus neighbors…';
  try{
    const days=Number(neighborPeriod.value);localStorage.setItem('recomendapp-neighbor-period',days);const from=Math.floor((Date.now()-days*86400000)/1000);const tracks=[];
    for(const name of currentNeighborNames){const limit=neighborStore[name]?.limit??250;const userTracks=await allScrobbles(name,from,limit,(user,loaded,total)=>btn.textContent=`${user}: ${loaded}/${total} scrobbles…`).catch(error=>{if(error.message==='__SYNC_CANCELLED__')throw error;return[]});tracks.push(...userTracks);}
    if(!tracks.length)throw new Error('No encontré scrobbles públicos en ese periodo.');
    stagedScrobbles=tracks;const uniqueCount=new Set(tracks.map(t=>`${t.artist}\u0000${t.name}`.toLowerCase())).size;scrobblePreviewTitle.textContent=`${tracks.length.toLocaleString()} escuchas`;scrobblePreviewMeta.textContent=`${uniqueCount.toLocaleString()} canciones únicas · límites individuales respetados`;scrobbleList.innerHTML=tracks.map((t,i)=>`<div class="scrobble-row"><span>${i+1}</span><strong>${escapeHtml(t.name)}</strong><span>${escapeHtml(t.artist)}</span><small>${escapeHtml(t.neighbor)} · ${t.uts?new Date(t.uts*1000).toLocaleDateString():'sin fecha'}</small></div>`).join('');scrobblePreview.hidden=false;scrobblePreview.scrollIntoView({behavior:'smooth',block:'start'});syncStage.textContent='Scrobbles listos';syncCurrent.textContent='Revisa la lista antes de crear las playlists.';syncBar.style.width='100%';notify(`${tracks.length} scrobbles encontrados`);return;
  }catch(e){if(e.message==='__SYNC_CANCELLED__'){syncStage.textContent='Búsqueda detenida';syncCurrent.textContent='Puedes volver a recopilar cuando quieras.';notify('Búsqueda detenida')}else notify(e.message);}finally{clearInterval(syncHintTimer);btn.disabled=false;cancelSyncBtn.disabled=true;btn.textContent='Ver scrobbles';}
}
async function youtubeFallback(tracks,btn){
  if(!tracks.length)return {trackIds:[],searched:0,cached:0};
  let config=await api.getConfig();if(!config.youtubeConnected){syncCurrent.textContent='Autoriza tu cuenta para continuar en YouTube.';await api.connectYouTube();setConnected('YouTube',true);config=await api.getConfig();}
  const cache=new Map(JSON.parse(localStorage.getItem('recomendapp-youtube-video-cache')||'[]'));let searched=0,paused=false;const dailyBudget=55;
  for(let i=0;i<tracks.length;i++){if(syncCancelled)throw new Error('__SYNC_CANCELLED__');const track=tracks[i];const key=`${track.artist}\u0000${track.name}`.toLowerCase();if(!cache.has(key)){if(searched>=dailyBudget){paused=true;syncHint.textContent=`Pausa preventiva de YouTube: ${dailyBudget} búsquedas nuevas. El resto continuará en la próxima ejecución.`;break;}btn.textContent=`YouTube: ${i+1}/${tracks.length}`;syncStage.textContent='Buscando faltantes en YouTube';syncNumbers.textContent=`${i+1} / ${tracks.length} · presupuesto ${searched}/${dailyBudget}`;syncCurrent.textContent=`YouTube: ${track.artist} — ${track.name}`;const q=encodeURIComponent(`${track.artist} ${track.name} official audio`);try{const result=await api.youtube(`/search?part=snippet&type=video&videoCategoryId=10&maxResults=1&q=${q}`,{timeoutMs:15000});cache.set(key,result.items?.[0]?.id?.videoId||'');searched++;localStorage.setItem('recomendapp-youtube-video-cache',JSON.stringify([...cache]));}catch(error){localStorage.setItem('recomendapp-youtube-video-cache',JSON.stringify([...cache]));if(/YOUTUBE_QUOTA_EXCEEDED|quota|limit|exceeded/i.test(error.message)){paused=true;syncHint.textContent='YouTube agotó la cuota de hoy. No se perdió el progreso; continúa mañana.';break;}throw error;}}}
  const pending=tracks.filter(t=>!cache.has(`${t.artist}\u0000${t.name}`.toLowerCase())).length;return {trackIds:[...new Set(tracks.map(t=>cache.get(`${t.artist}\u0000${t.name}`.toLowerCase())).filter(Boolean))],searched,cached:tracks.length-pending-searched,pending,paused};
}
async function createCatalogPlaylists(){
  if(!stagedScrobbles.length){notify('Primero recopila y revisa los scrobbles');return;}const btn=createCatalogPlaylistsBtn;syncCancelled=false;api.setProcessActive(true);btn.disabled=true;syncPlaylistBtn.disabled=true;cancelSyncBtn.disabled=false;syncProgress.hidden=false;startSyncHints();
  try{const resolved=await spotifyUrisFast(stagedScrobbles,btn);let spotifyUrl='';if(resolved.uris.length){let playlistId=localStorage.getItem('recomendapp-neighbors-playlist');spotifyUrl=localStorage.getItem('recomendapp-neighbors-playlist-url')||'';if(!playlistId){const created=await api.spotify('/me/playlists',{method:'POST',body:{name:'Neighbors — Recomendapp',public:false,description:'Scrobbles de mis vecinos. Las canciones no disponibles se envían a YouTube.'}});playlistId=created.id;spotifyUrl=created.external_urls?.spotify||'';localStorage.setItem('recomendapp-neighbors-playlist',playlistId);localStorage.setItem('recomendapp-neighbors-playlist-url',spotifyUrl);}syncStage.textContent='Guardando playlist de Spotify';await api.spotify(`/playlists/${playlistId}/items`,{method:'PUT',body:{uris:resolved.uris.slice(0,100)}});for(let i=100;i<resolved.uris.length;i+=100)await api.spotify(`/playlists/${playlistId}/items`,{method:'POST',body:{uris:resolved.uris.slice(i,i+100)}});}
    let youtubeUrl='',youtubeCount=0;if(resolved.missing.length){const yt=await youtubeFallback(resolved.missing,btn);youtubeCount=yt.trackIds.length;if(yt.trackIds.length){syncStage.textContent='Creando playlist de YouTube';const playlist=await api.youtube('/playlists?part=snippet,status',{method:'POST',body:{snippet:{title:'Neighbors — Recomendapp',description:'Canciones no encontradas en Spotify.'},status:{privacyStatus:'private'}}});for(const videoId of yt.trackIds)await api.youtube('/playlistItems?part=snippet',{method:'POST',body:{snippet:{playlistId:playlist.id,resourceId:{kind:'youtube#video',videoId}}}});youtubeUrl=`https://www.youtube.com/playlist?list=${playlist.id}`;}}
    syncStage.textContent='Playlists listas';syncCurrent.textContent=`Spotify: ${resolved.uris.length} · YouTube: ${youtubeCount} · Sin coincidencia: ${Math.max(0,resolved.missing.length-youtubeCount)}`;syncBar.style.width='100%';notify('Playlists creadas correctamente');if(spotifyUrl)window.open(spotifyUrl,'_blank');if(youtubeUrl)window.open(youtubeUrl,'_blank');
  }catch(error){if(error.message.includes('__SYNC_CANCELLED__')||error.message.includes('SPOTIFY_CANCELLED')||error.message.includes('YOUTUBE_CANCELLED')){syncStage.textContent='Búsqueda detenida';syncCurrent.textContent='El progreso quedó guardado.';}else if(error.message.includes('YOUTUBE_QUOTA_EXCEEDED')){syncStage.textContent='Cuota de YouTube agotada';syncCurrent.textContent='No se perdió el progreso. Continúa mañana para completar la playlist.';notify('YouTube alcanzó su cuota diaria');}else if(/scope|permission|403/i.test(error.message)){notify('La cuenta necesita autorización. Vuelve a conectar el servicio.');}else notify(error.message);}finally{clearInterval(syncHintTimer);btn.disabled=false;syncPlaylistBtn.disabled=false;cancelSyncBtn.disabled=true;btn.textContent='Crear playlists';api.setProcessActive(false);}
}
