async function loadSpotifyPlaylists(){if(!api)return;sourcePlaylist.innerHTML=referencePlaylist.innerHTML='<option>Cargando…</option>';try{let items=[],offset=0,data;do{data=await api.spotify(`/me/playlists?limit=50&offset=${offset}`);items.push(...(data.items||[]).filter(Boolean));offset+=50;}while(data.next&&offset<500);const options=items.map(p=>`<option value="${p.id}">${escapeHtml(p.name)} (${p.items?.total??p.tracks?.total??0})</option>`).join('');sourcePlaylist.innerHTML=options;referencePlaylist.innerHTML=options;if(items.length>1)referencePlaylist.selectedIndex=1;}catch(e){if(/scope|permission|403/i.test(e.message)){notify('Autoriza Spotify para leer tus playlists');await api.connectSpotify();return loadSpotifyPlaylists();}notify(e.message)}}
async function playlistItems(id,onProgress){let items=[],offset=0,data;do{data=await api.spotify(`/playlists/${id}/items?limit=50&offset=${offset}`);items.push(...(data.items||[]));offset+=data.limit||50;if(onProgress)onProgress(items.length,data.total||items.length);}while(data.next);return items.map(row=>row.item||row.track).filter(t=>t?.type==='track'&&t.uri).map(t=>({uri:t.uri,name:t.name,artist:(t.artists||[]).map(a=>a.name).join(', '),artistIds:(t.artists||[]).map(a=>a.id)}));}
