document.querySelector('#compareBtn').addEventListener('click',async()=>{if(sourcePlaylist.value===referencePlaylist.value){notify('Selecciona dos playlists diferentes');return;}compareBtn.disabled=true;compareBtn.textContent='Leyendo playlists…';try{let sourceProgress='0',referenceProgress='0';const updateProgress=()=>compareBtn.textContent=`Cargando ${sourceProgress} + ${referenceProgress} canciones…`;const [source,reference]=await Promise.all([playlistItems(sourcePlaylist.value,(loaded,total)=>{sourceProgress=`${loaded}/${total}`;updateProgress()}),playlistItems(referencePlaylist.value,(loaded,total)=>{referenceProgress=`${loaded}/${total}`;updateProgress()})]);compareBtn.textContent='Calculando diferencia…';const known=new Set(reference.flatMap(t=>compareMode==='artist'?t.artistIds:[t.uri]));compareTracks=source.filter(t=>compareMode==='artist'?t.artistIds.length&&t.artistIds.every(id=>!known.has(id)):!known.has(t.uri));resultTitle.textContent=`${compareTracks.length} canciones nuevas`;resultTracks.innerHTML=`<div class="neighbor-meta">Analizadas ${source.length.toLocaleString()} canciones fuente contra ${reference.length.toLocaleString()} de referencia · filtro por ${compareMode==='artist'?'artistas':'canciones'}</div>`+(compareTracks.length?compareTracks.map((t,i)=>`<div class="result-track"><span>${String(i+1).padStart(2,'0')}</span><strong>${escapeHtml(t.name)}</strong><span>${escapeHtml(t.artist)}</span></div>`).join(''):'<div class="neighbors-status">No hay elementos nuevos con este filtro.</div>');compareResult.hidden=false;}catch(e){notify(e.message)}finally{compareBtn.disabled=false;compareBtn.textContent='Comparar playlists →'}});
document.querySelector('#saveCompareBtn').addEventListener('click',async()=>{if(!compareTracks.length)return;saveCompareBtn.disabled=true;try{const sourceName=sourcePlaylist.options[sourcePlaylist.selectedIndex].text.replace(/ \(\d+\)$/,'');const created=await api.spotify('/me/playlists',{method:'POST',body:{name:`${sourceName} — solo nuevo`,public:false,description:`Resultado de Compare por ${compareMode==='artist'?'artistas':'canciones'} en Recomendapp.`}});for(let i=0;i<compareTracks.length;i+=100)await api.spotify(`/playlists/${created.id}/items`,{method:'POST',body:{uris:compareTracks.slice(i,i+100).map(t=>t.uri)}});notify('Playlist nueva creada en Spotify');window.open(created.external_urls.spotify,'_blank');}catch(e){notify(e.message)}finally{saveCompareBtn.disabled=false}});

