async function loadCompareV1Playlists(){if(!api)return;primaryPlaylist.innerHTML='<option>Cargando…</option>';comparePlaylistChoices.innerHTML='<div class="neighbors-status">Leyendo tu biblioteca…</div>';try{let items=[],offset=0,data;do{data=await api.spotify(`/me/playlists?limit=50&offset=${offset}`);items.push(...(data.items||[]).filter(Boolean));offset+=50;}while(data.next&&offset<1000);compareV1Playlists=items;primaryPlaylist.innerHTML=items.map(p=>`<option value="${p.id}">${escapeHtml(p.name)} (${p.items?.total??p.tracks?.total??0})</option>`).join('');const saved=localStorage.getItem('recomendapp-primary-playlist');if(saved&&items.some(p=>p.id===saved))primaryPlaylist.value=saved;renderCompareChoices();}catch(error){if(/scope|permission|403/i.test(error.message)){notify('Autoriza Spotify para leer tus playlists');await api.connectSpotify();return loadCompareV1Playlists()}notify(error.message)}}
