compareV1Btn.addEventListener('click',async()=>{const ids=[...comparePlaylistChoices.querySelectorAll('input:checked')].map(input=>input.value);if(!primaryPlaylist.value||!ids.length){notify('Elige una playlist primaria y al menos otra para contrastar');return}compareV1Btn.disabled=true;try{compareV1Btn.textContent='Leyendo tu mundo…';const primary=await playlistItems(primaryPlaylist.value,(loaded,total)=>compareV1Btn.textContent=`Tu mundo ${loaded}/${total}`);const sources=[];for(let i=0;i<ids.length;i++){compareV1Btn.textContent=`Leyendo playlist ${i+1}/${ids.length}…`;sources.push(...await playlistItems(ids[i]));}const known=new Set(primary.flatMap(track=>compareV1Mode==='artist'?track.artistIds:[track.uri]));compareV1Tracks=[...new Map(sources.filter(track=>compareV1Mode==='artist'?track.artistIds.length&&track.artistIds.every(id=>!known.has(id)):!known.has(track.uri)).map(track=>[track.uri,track])).values()];resultV1Title.textContent=`${compareV1Tracks.length.toLocaleString()} canciones nuevas`;resultV1Tracks.innerHTML=`<div class="neighbor-meta">${primary.length.toLocaleString()} conocidas · ${sources.length.toLocaleString()} candidatas · ${ids.length} playlists humanas</div>`+(compareV1Tracks.length?compareV1Tracks.map((track,index)=>`<div class="result-track"><span>${String(index+1).padStart(2,'0')}</span><strong><a class="song-link" href="${spotifyTrackUrl(track)}" target="_blank">${escapeHtml(track.name)}</a></strong><span>${escapeHtml(track.artist)}</span></div>`).join(''):'<div class="neighbors-status">No encontramos novedades con este criterio.</div>');compareV1Result.hidden=false;}catch(error){notify(error.message)}finally{compareV1Btn.disabled=false;compareV1Btn.textContent='Encontrar novedades →'}});
compareCover.addEventListener('change',async()=>{const file=compareCover.files?.[0];if(!file)return;const image=await createImageBitmap(file),canvas=document.createElement('canvas');canvas.width=canvas.height=300;const context=canvas.getContext('2d'),side=Math.min(image.width,image.height);context.drawImage(image,(image.width-side)/2,(image.height-side)/2,side,side,0,0,300,300);compareCoverData=canvas.toDataURL('image/jpeg',.82);notify('Imagen preparada para la nueva playlist')});
saveCompareV1Btn.addEventListener('click',async()=>{if(!compareV1Tracks.length)return;saveCompareV1Btn.disabled=true;try{const sourceNames=[...comparePlaylistChoices.querySelectorAll('input:checked')].map(input=>compareV1Playlists.find(p=>p.id===input.value)?.name).filter(Boolean),name=`Descubrimientos · ${sourceNames.slice(0,2).join(' + ')}${sourceNames.length>2?` +${sourceNames.length-2}`:''}`;const created=await api.spotify('/me/playlists',{method:'POST',body:{name,public:false,description:`Novedades humanas comparadas contra ${primaryPlaylist.options[primaryPlaylist.selectedIndex]?.text}.`}});for(let i=0;i<compareV1Tracks.length;i+=100)await api.spotify(`/playlists/${created.id}/items`,{method:'POST',body:{uris:compareV1Tracks.slice(i,i+100).map(t=>t.uri)}});if(compareCoverData)await api.spotifyUploadCover(created.id,compareCoverData);const internalId=await api.libraryCreate(name,'compare',compareV1Tracks);await api.libraryUpdatePlaylist(internalId,{spotify_id:created.id,cover_image:compareCoverData||null});const internal=await api.libraryGet(internalId),uriByKey=new Map(compareV1Tracks.map(t=>[trackCacheKey(t),t.uri]));for(const track of internal.tracks)await api.libraryUpdateTrack(track.id,{spotify_uri:uriByKey.get(track.track_key),spotify_status:'added'});notify('Playlist creada y guardada en tu biblioteca interna');window.open(created.external_urls.spotify,'_blank');}catch(error){if(/scope|permission|403/i.test(error.message))notify('Reconecta Spotify para autorizar portadas de playlist');else notify(error.message)}finally{saveCompareV1Btn.disabled=false}});
async function loadSongs(selectedId){const playlists=await api.libraryList();songsPlaylist.innerHTML=playlists.map(p=>`<option value="${p.id}">${escapeHtml(p.name)} (${p.total||0})</option>`).join('');songsTargetPlaylist.innerHTML=playlists.map(p=>`<option value="${p.id}">${escapeHtml(p.name)}</option>`).join('');if(selectedId)songsPlaylist.value=selectedId;if(!songsPlaylist.value){songsList.innerHTML='<div class="neighbors-status">Crea una playlist desde Compare o Labs.</div>';songsCount.textContent='0 canciones';return}const data=await api.libraryGet(Number(songsPlaylist.value));songsCount.textContent=`${data.tracks.length.toLocaleString()} canciones`;songsList.innerHTML=data.tracks.map((track,index)=>{const hasSpotify=!!track.spotify_uri||track.spotify_status==='added',hasLastfm=data.playlist.source!=='compare'||tagCache.has(track.track_key);return `<div class="song-row" data-track-id="${track.id}"><span>${index+1}</span><strong><a class="song-link" href="${spotifyTrackUrl(track)}" target="_blank">${escapeHtml(track.name)}</a></strong><span>${escapeHtml(track.artist)}</span><div class="song-badges">${hasSpotify?'<i class="song-badge spotify">Spotify</i>':''}${hasLastfm?'<i class="song-badge lastfm">Last.fm</i>':''}</div><div><button class="song-add" title="Añadir a la playlist elegida">＋</button><button class="song-remove" title="Eliminar">×</button></div></div>`}).join('')};
songsPlaylist.addEventListener('change',()=>loadSongs());songsList.addEventListener('click',async event=>{const row=event.target.closest('[data-track-id]');if(!row)return;const source=await api.libraryGet(Number(songsPlaylist.value)),track=source.tracks.find(t=>Number(t.id)===Number(row.dataset.trackId));if(event.target.closest('.song-remove')){await api.libraryRemoveTrack(track.id);notify('Canción eliminada de esta playlist');await loadSongs(songsPlaylist.value)}if(event.target.closest('.song-add')){if(Number(songsTargetPlaylist.value)===Number(songsPlaylist.value)){notify('Elige otra playlist de destino');return}await api.libraryAddTracks(Number(songsTargetPlaylist.value),[track]);notify('Canción añadida a la playlist elegida')}});

let globalSearchItems=[];
async function refreshGlobalSearchPlaylists(){const playlists=await api.libraryList();globalSearchPlaylist.innerHTML=playlists.map(p=>`<option value="${p.id}">${escapeHtml(p.name)}</option>`).join('')||'<option value="">Primero crea una playlist</option>'}
globalSearchForm.addEventListener('submit',async event=>{event.preventDefault();const query=globalSearchInput.value.trim();if(!query)return;globalSearchPanel.hidden=false;globalSearchStatus.textContent='Buscando en Spotify y Last.fm…';globalSearchResults.innerHTML='';await refreshGlobalSearchPlaylists();try{const [spotify,lastfm]=await Promise.all([api.spotify(`/search?q=${encodeURIComponent(query)}&type=track&limit=12`).catch(()=>({tracks:{items:[]}})),api.lastfm('track.search',{track:query,limit:'12'}).catch(()=>({results:{trackmatches:{track:[]}}}))]);const combined=new Map();for(const track of spotify.tracks?.items||[]){const artist=(track.artists||[]).map(a=>a.name).join(', '),key=`${artist}\u0000${track.name}`.toLowerCase();combined.set(key,{name:track.name,artist,uri:track.uri,spotify:true,lastfm:false,url:track.external_urls?.spotify})}for(const track of lastfm.results?.trackmatches?.track||[]){const key=`${track.artist}\u0000${track.name}`.toLowerCase(),current=combined.get(key);if(current)current.lastfm=true;else combined.set(key,{name:track.name,artist:track.artist,spotify:false,lastfm:true,url:track.url})}globalSearchItems=[...combined.values()];globalSearchStatus.textContent=`${globalSearchItems.length} coincidencias`;globalSearchResults.innerHTML=globalSearchItems.map((track,index)=>`<article class="global-result"><div><a href="${escapeHtml(track.url||spotifyTrackUrl(track))}" target="_blank">${escapeHtml(track.name)}</a><span>${escapeHtml(track.artist)}</span></div><div class="song-badges">${track.spotify?'<i class="song-badge spotify">Spotify</i>':''}${track.lastfm?'<i class="song-badge lastfm">Last.fm</i>':''}</div><button data-search-add="${index}">＋ Añadir</button></article>`).join('')||'<div class="neighbors-status">No encontramos esa canción.</div>';}catch(error){globalSearchStatus.textContent=error.message}});
globalSearchResults.addEventListener('click',async event=>{const button=event.target.closest('[data-search-add]');if(!button)return;const playlistId=Number(globalSearchPlaylist.value),track=globalSearchItems[Number(button.dataset.searchAdd)];if(!playlistId||!track){notify('Crea o selecciona una playlist interna');return}await api.libraryAddTracks(playlistId,[track]);const data=await api.libraryGet(playlistId),saved=data.tracks.find(item=>item.track_key===trackCacheKey(track));if(track.uri&&saved)await api.libraryUpdateTrack(saved.id,{spotify_uri:track.uri,spotify_status:'found'});button.textContent='Añadida ✓';button.disabled=true;notify(`${track.name} añadida a ${data.playlist.name}`)});closeGlobalSearch.addEventListener('click',()=>globalSearchPanel.hidden=true);

async function allUserPlaylists(userId){let items=[],offset=0,data;do{data=await api.spotify(`/users/${encodeURIComponent(userId)}/playlists?limit=50&offset=${offset}`);items.push(...(data.items||[]).filter(Boolean));offset+=50;}while(data.next);return items;}
document.querySelector('#loadFollowedBtn').addEventListener('click',async()=>{const profiles=Object.entries(neighborStore).map(([name,value])=>({name,id:spotifyId(value.spotify||'')})).filter(p=>p.id);if(!profiles.length){followedPlaylists.innerHTML='<p class="neighbors-status">Vincula el perfil de Spotify de al menos un neighbor.</p>';return;}loadFollowedBtn.disabled=true;followedPlaylists.innerHTML='<p class="neighbors-status">Cargando todas las playlists disponibles…</p>';try{const groups=await Promise.all(profiles.map(async profile=>({profile,playlists:await allUserPlaylists(profile.id)})));followedPlaylists.innerHTML=groups.flatMap(({profile,playlists})=>playlists.map(p=>`<button class="followed-card" data-playlist-id="${escapeHtml(p.id)}" data-playlist-name="${escapeHtml(p.name)}"><strong>${escapeHtml(p.name)}</strong><span>${escapeHtml(profile.name)} · ${(p.items?.total??p.tracks?.total??0).toLocaleString()} canciones</span></button>`)).join('')||'<p class="neighbors-status">No hay playlists públicas disponibles.</p>';}catch(error){followedPlaylists.innerHTML=`<p class="neighbors-status">${escapeHtml(error.message)}</p>`;}finally{loadFollowedBtn.disabled=false;}});
const tagCache=new Map(JSON.parse(localStorage.getItem('recomendapp-track-tags-cache')||'[]'));
async function tagsForTrack(track){const key=`${track.artist}\u0000${track.name}`.toLowerCase();if(tagCache.has(key))return tagCache.get(key);try{const data=await api.lastfm('track.getTopTags',{artist:track.artist,name:track.name,track:track.name,autocorrect:'1'});const tags=(data.toptags?.tag||[]).slice(0,5).map(t=>t.name);tagCache.set(key,tags);localStorage.setItem('recomendapp-track-tags-cache',JSON.stringify([...tagCache]));return tags;}catch{return[];}}
document.querySelector('#followedPlaylists').addEventListener('click',async event=>{const card=event.target.closest('.followed-card');if(!card)return;playlistDetailTitle.textContent=card.dataset.playlistName;playlistDetailStatus.textContent='Leyendo canciones y tags…';playlistDetailTracks.innerHTML='';playlistDetailDialog.showModal();try{const tracks=await playlistItems(card.dataset.playlistId);playlistDetailStatus.textContent=`${tracks.length} canciones · tags aportados por Last.fm`;const rows=[];for(let i=0;i<tracks.length;i+=4){const batch=tracks.slice(i,i+4);const tags=await Promise.all(batch.map(tagsForTrack));batch.forEach((track,j)=>rows.push(`<div class="result-track"><span>${rows.length+1}</span><strong>${escapeHtml(track.name)}</strong><span>${escapeHtml(track.artist)}</span><div class="track-tags">${tags[j].map(tag=>`<i>${escapeHtml(tag)}</i>`).join('')||'<i>sin tags</i>'}</div></div>`));playlistDetailStatus.textContent=`Etiquetando ${Math.min(i+4,tracks.length)} / ${tracks.length}…`;playlistDetailTracks.innerHTML=rows.join('');}playlistDetailStatus.textContent=`${tracks.length} canciones · tags de Last.fm`;}catch(error){playlistDetailStatus.textContent=/403/.test(error.message)?'Spotify restringió la lectura de esta playlist ajena. Puedes abrirla directamente en Spotify.':error.message;}});
document.querySelector('#closePlaylistDetail').addEventListener('click',()=>playlistDetailDialog.close());

const maxicoverSelected=new Set(),maxicoverRelatedMap=new Map();let artistSearchTimer,artistSearchSequence=0;
function renderMaxicoverArtists(){maxicoverArtists.innerHTML=[...maxicoverSelected].map(name=>`<button class="maxicover-chip" data-artist="${escapeHtml(name)}">${escapeHtml(name)} ×</button>`).join('');}
function renderMaxicoverRelated(){const selected=[...maxicoverRelatedMap.values()].filter(a=>a.selected).length;maxicoverRelatedCount.textContent=`${selected} / ${maxicoverRelatedMap.size} incluidos`;maxicoverRelated.innerHTML=[...maxicoverRelatedMap.values()].map(a=>`<button class="related-artist ${a.selected?'selected':''}" data-related="${escapeHtml(a.name)}">${escapeHtml(a.name)}${a.match?` · ${Math.round(Number(a.match)*100)}%`:''}</button>`).join('');maxicoverRelatedSection.hidden=!maxicoverRelatedMap.size;}
async function refreshMaxicoverRelated(){maxicoverRelatedMap.clear();renderMaxicoverRelated();for(const seed of maxicoverSelected){maxicoverRelatedCount.textContent=`Buscando relacionados de ${seed}…`;try{const data=await api.lastfm('artist.getSimilar',{artist:seed,limit:'1000',autocorrect:'1'});for(const artist of data.similarartists?.artist||[]){const key=artist.name.toLowerCase();if(!maxicoverRelatedMap.has(key))maxicoverRelatedMap.set(key,{name:artist.name,match:artist.match,selected:true});}}catch(error){notify(error.message);}}renderMaxicoverRelated();}
async function addMaxicoverArtist(chosenName){let name=String(chosenName||maxicoverArtist.value).trim();if(!name)return;if(!chosenName){try{const data=await api.lastfm('artist.search',{artist:name,limit:'1'});name=data.results?.artistmatches?.artist?.[0]?.name||'';}catch{}if(!name){notify('Last.fm no encontró ese artista');return;}}maxicoverSelected.add(name);maxicoverArtist.value='';maxicoverSuggestions.hidden=true;renderMaxicoverArtists();await refreshMaxicoverRelated();}
async function searchArtistSuggestions(query,sequence){try{const data=await api.lastfm('artist.search',{artist:query,limit:'8'});if(sequence!==artistSearchSequence)return;const matches=data.results?.artistmatches?.artist||[];maxicoverSuggestions.innerHTML=matches.map(a=>`<button class="artist-suggestion" data-suggestion="${escapeHtml(a.name)}"><strong>${escapeHtml(a.name)}</strong><small>${Number(a.listeners||0).toLocaleString()} oyentes</small></button>`).join('')||'<div class="artist-suggestion">Sin coincidencias</div>';maxicoverSuggestions.hidden=false;}catch{maxicoverSuggestions.hidden=true;}}
document.querySelector('#maxicoverArtist').addEventListener('input',()=>{clearTimeout(artistSearchTimer);const query=maxicoverArtist.value.trim();const sequence=++artistSearchSequence;if(query.length<2){maxicoverSuggestions.hidden=true;return;}artistSearchTimer=setTimeout(()=>searchArtistSuggestions(query,sequence),300);});
document.querySelector('#maxicoverSuggestions').addEventListener('click',e=>{const item=e.target.closest('[data-suggestion]');if(item)addMaxicoverArtist(item.dataset.suggestion);});document.querySelector('#addMaxicoverArtist').addEventListener('click',()=>addMaxicoverArtist());document.querySelector('#maxicoverArtist').addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();addMaxicoverArtist();}});document.querySelector('#maxicoverArtists').addEventListener('click',async e=>{const chip=e.target.closest('.maxicover-chip');if(chip){maxicoverSelected.delete(chip.dataset.artist);renderMaxicoverArtists();await refreshMaxicoverRelated();}});document.querySelector('#maxicoverRelated').addEventListener('click',e=>{const item=e.target.closest('[data-related]');if(!item)return;const related=maxicoverRelatedMap.get(item.dataset.related.toLowerCase());related.selected=!related.selected;renderMaxicoverRelated();});
async function maxicoverRecommendations(){const names=[...maxicoverRelatedMap.values()].filter(a=>a.selected).map(a=>a.name);if(!names.length)throw new Error('Selecciona al menos un artista relacionado.');const tracks=[];let cursor=0;async function worker(){while(cursor<names.length&&!syncCancelled){const index=cursor++,name=names[index];maxicoverNumbers.textContent=`${index+1} / ${names.length} artistas recomendados`;maxicoverCurrent.textContent=`Last.fm recomienda una canción de ${name}`;try{const data=await api.lastfm('artist.getTopTracks',{artist:name,limit:'1',autocorrect:'1'});tracks.push(...(data.toptracks?.track||[]).map(t=>({name:t.name,artist:t.artist?.name||name})));}catch{}}}await Promise.all(Array.from({length:4},worker));return [...new Map(tracks.map(t=>[`${t.artist}\u0000${t.name}`.toLowerCase(),t])).values()];}
document.querySelector('#runMaxicover').addEventListener('click',async()=>{if(!maxicoverSelected.size){notify('Añade al menos un artista');return;}syncCancelled=false;api.setProcessActive(true);runMaxicover.disabled=true;maxicoverProgress.hidden=false;cancelMaxicover.disabled=false;try{const tracks=await maxicoverRecommendations();if(syncCancelled)throw new Error('__SYNC_CANCELLED__');const libraryKey=[...maxicoverSelected].map(v=>v.toLowerCase()).sort().join('|');let internalId=Number(localStorage.getItem(`recomendapp-library-${libraryKey}`)||0);if(internalId)await api.libraryAddTracks(internalId,tracks);else{internalId=await api.libraryCreate(`Maxicover — ${[...maxicoverSelected].join(' + ')}`,'maxicover',tracks);localStorage.setItem(`recomendapp-library-${libraryKey}`,String(internalId));}notify(`${tracks.length} recomendaciones guardadas en la playlist interna`);maxicoverStage.textContent=`Guardadas ${tracks.length} canciones · sincronizando`;const resolved=await spotifyUrisFast(tracks,runMaxicover);let spotifyUrl='';if(resolved.uris.length){const created=await api.spotify('/me/playlists',{method:'POST',body:{name:`Maxicover — ${[...maxicoverSelected].join(' + ')}`,public:false,description:'Recomendaciones expandidas desde Last.fm por Recomendapp.'}});await api.libraryUpdatePlaylist(internalId,{spotify_id:created.id});for(let i=0;i<resolved.uris.length;i+=100)await api.spotify(`/playlists/${created.id}/items`,{method:'POST',body:{uris:resolved.uris.slice(i,i+100)}});spotifyUrl=created.external_urls?.spotify||'';}let youtubeUrl='',youtubeFound=0,youtubePending=0;if(resolved.missing.length){const yt=await youtubeFallback(resolved.missing,runMaxicover);youtubeFound=yt.trackIds.length;youtubePending=yt.pending;if(yt.trackIds.length){try{let playlistId=localStorage.getItem('recomendapp-maxicover-youtube-playlist');youtubeUrl=localStorage.getItem('recomendapp-maxicover-youtube-url')||'';if(!playlistId){const playlist=await api.youtube('/playlists?part=snippet,status',{method:'POST',body:{snippet:{title:`Maxicover — ${[...maxicoverSelected].join(' + ')}`},status:{privacyStatus:'private'}}});playlistId=playlist.id;youtubeUrl=`https://www.youtube.com/playlist?list=${playlist.id}`;localStorage.setItem('recomendapp-maxicover-youtube-playlist',playlistId);localStorage.setItem('recomendapp-maxicover-youtube-url',youtubeUrl);await api.libraryUpdatePlaylist(internalId,{youtube_id:playlistId,youtube_url:youtubeUrl});}const inserted=new Set(JSON.parse(localStorage.getItem('recomendapp-maxicover-youtube-inserted')||'[]'));for(const videoId of yt.trackIds){if(inserted.has(videoId))continue;await api.youtube('/playlistItems?part=snippet',{method:'POST',body:{snippet:{playlistId,resourceId:{kind:'youtube#video',videoId}}}});inserted.add(videoId);localStorage.setItem('recomendapp-maxicover-youtube-inserted',JSON.stringify([...inserted]));}}catch(error){if(!error.message.includes('YOUTUBE_QUOTA_EXCEEDED'))throw error;youtubePending+=yt.trackIds.length;}}}maxicoverStage.textContent=youtubePending?'Guardado internamente · sincronización parcial':'Maxicover listo';maxicoverNumbers.textContent=`Spotify ${resolved.uris.length} · YouTube ${youtubeFound} · pendientes ${youtubePending}`;maxicoverBar.style.width='100%';if(youtubePending)notify(`Todo quedó guardado. Quedan ${youtubePending} sincronizaciones pendientes.`);if(spotifyUrl)window.open(spotifyUrl,'_blank');if(youtubeUrl)window.open(youtubeUrl,'_blank');}catch(error){if(!/CANCELLED/.test(error.message))notify(error.message.includes('YOUTUBE_QUOTA_EXCEEDED')?'YouTube agotó la cuota diaria. El progreso está guardado.':error.message);maxicoverStage.textContent=syncCancelled?'Proceso detenido':'Proceso pausado';}finally{runMaxicover.disabled=false;cancelMaxicover.disabled=true;api.setProcessActive(false);}});
document.querySelector('#cancelMaxicover').addEventListener('click',async()=>{syncCancelled=true;cancelMaxicover.disabled=true;await Promise.all([api.cancelSpotify('neighbors-sync'),api.cancelYouTube()]);maxicoverStage.textContent='Proceso detenido';api.setProcessActive(false);});

let activeLibraryId=0;
let externalLibraryPlaylists={spotify:[],youtube:[]};
let activeExternalPlaylist='';
const trackCacheKey=track=>`${track.artist}\u0000${track.name}`.toLowerCase();
const libraryStatusLabel=track=>track.spotify_status==='added'?'Spotify':track.youtube_status==='added'?'YouTube':track.last_error?'Fallida':'Pendiente';
function renderLibrarySources(playlists,selected){const internal=playlists.map(item=>`<button class="library-card ${Number(item.id)===Number(selected)?'active':''}" data-library-id="${item.id}">${item.cover_image?`<img src="${item.cover_image}" alt="">`:''}<i class="platform-tag internal">Recomendapp</i><strong>${escapeHtml(item.name)}</strong><span>${Number(item.total||0).toLocaleString()} canciones</span></button>`).join('');const spotify=externalLibraryPlaylists.spotify.map(item=>`<button class="library-card external ${activeExternalPlaylist===`spotify:${item.id}`?'active':''}" data-external-provider="spotify" data-external-id="${item.id}">${item.image?`<img src="${escapeHtml(item.image)}" alt="">`:''}<i class="platform-tag spotify">Spotify</i><strong>${escapeHtml(item.name)}</strong><span>${Number(item.total||0).toLocaleString()} canciones</span></button>`).join('');const youtube=externalLibraryPlaylists.youtube.map(item=>`<button class="library-card external ${activeExternalPlaylist===`youtube:${item.id}`?'active':''}" data-external-provider="youtube" data-external-id="${item.id}">${item.image?`<img src="${escapeHtml(item.image)}" alt="">`:''}<i class="platform-tag youtube">YouTube</i><strong>${escapeHtml(item.name)}</strong><span>${Number(item.total||0).toLocaleString()} videos</span></button>`).join('');libraryPlaylists.innerHTML=`<div class="library-group-title">RECOMENDAPP</div>${internal||'<div class="library-empty">Sin playlists internas</div>'}<div class="library-group-title">SPOTIFY</div>${spotify||'<div class="library-empty">No disponibles</div>'}<div class="library-group-title">YOUTUBE</div>${youtube||'<div class="library-empty">No disponibles o cuenta sin conectar</div>'}`;}
async function loadInternalPlaylists(selectId=activeLibraryId){
  const playlists=await api.libraryList();
  renderLibrarySources(playlists,selectId);
  Promise.all([api.spotify('/me/playlists?limit=50').then(data=>externalLibraryPlaylists.spotify=(data.items||[]).filter(Boolean).map(p=>({id:p.id,name:p.name,url:p.external_urls?.spotify,total:p.items?.total??p.tracks?.total??0,image:p.images?.[0]?.url}))).catch(()=>[]),api.getConfig().then(config=>config.youtubeConnected?api.youtube('/playlists?part=snippet,contentDetails&mine=true&maxResults=50').then(data=>externalLibraryPlaylists.youtube=(data.items||[]).map(p=>({id:p.id,name:p.snippet?.title,total:p.contentDetails?.itemCount||0,image:p.snippet?.thumbnails?.medium?.url}))):[]).catch(()=>[])]).finally(()=>renderLibrarySources(playlists,selectId));
  if(selectId&&playlists.some(item=>Number(item.id)===Number(selectId)))await showInternalPlaylist(selectId);
}
async function showInternalPlaylist(id){
  activeLibraryId=Number(id);const data=await api.libraryGet(activeLibraryId);if(!data.playlist)return;
  const spotifyCache=new Map(JSON.parse(localStorage.getItem('recomendapp-track-uri-cache')||'[]'));
  const youtubeCache=new Map(JSON.parse(localStorage.getItem('recomendapp-youtube-video-cache')||'[]'));
  if(data.playlist.spotify_id||data.playlist.youtube_id){for(const track of data.tracks){const changes={};const key=trackCacheKey(track);if(data.playlist.spotify_id&&track.spotify_status==='pending'&&spotifyCache.get(key)){changes.spotify_uri=spotifyCache.get(key);changes.spotify_status='added';}if(data.playlist.youtube_id&&track.youtube_status==='pending'&&youtubeCache.get(key)&&!spotifyCache.get(key)){changes.youtube_video_id=youtubeCache.get(key);changes.youtube_status='added';}if(Object.keys(changes).length)await api.libraryUpdateTrack(track.id,changes);}}
  const fresh=await api.libraryGet(activeLibraryId),counts=fresh.tracks.reduce((acc,t)=>(acc[libraryStatusLabel(t)]=(acc[libraryStatusLabel(t)]||0)+1,acc),{});
  libraryDetail.innerHTML=`<div class="library-detail-head">${fresh.playlist.cover_image?`<img class="library-cover" src="${fresh.playlist.cover_image}" alt="">`:'<div class="library-cover placeholder">♫</div>'}<div><span class="kicker">${escapeHtml(fresh.playlist.source)}</span><h2>${escapeHtml(fresh.playlist.name)}</h2><p>${fresh.tracks.length.toLocaleString()} canciones · Spotify ${counts.Spotify||0} · YouTube ${counts.YouTube||0} · pendientes ${(counts.Pendiente||0)+(counts.Fallida||0)}</p></div><div class="library-actions"><label class="cover-picker">Editar imagen<input type="file" accept="image/jpeg,image/png" data-library-cover></label><button data-library-sync>Sincronizar ahora</button><button data-library-retry>Reintentar fallidas</button>${fresh.playlist.spotify_id?`<a href="https://open.spotify.com/playlist/${escapeHtml(fresh.playlist.spotify_id)}" target="_blank">Abrir Spotify ↗</a>`:''}${fresh.playlist.youtube_url?`<a href="${escapeHtml(fresh.playlist.youtube_url)}" target="_blank">Abrir YouTube ↗</a>`:''}</div></div><div class="library-sync-message" data-library-message>Todo lo pendiente se conserva aunque cierres la app.</div><div class="library-tracks">${fresh.tracks.map((track,index)=>`<div class="library-track"><span>${index+1}</span><div><strong><a class="song-link" href="${spotifyTrackUrl(track)}" target="_blank">${escapeHtml(track.name)}</a></strong><small>${escapeHtml(track.artist)}</small></div><i class="status-${libraryStatusLabel(track).toLowerCase()}">${libraryStatusLabel(track)}</i></div>`).join('')}</div>`;
  await loadInternalPlaylistsCardsOnly(activeLibraryId);
}
async function loadInternalPlaylistsCardsOnly(selected){renderLibrarySources(await api.libraryList(),selected);}
async function syncInternalPlaylist(id){
  const data=await api.libraryGet(id),button=libraryDetail.querySelector('[data-library-sync]'),message=libraryDetail.querySelector('[data-library-message]');if(!data.playlist||!data.tracks.length)return;syncCancelled=false;api.setProcessActive(true);button.disabled=true;
  try{
    message.textContent='Buscando coincidencias pendientes en Spotify…';const spotifyTargets=data.tracks.filter(t=>t.spotify_status!=='added'&&t.youtube_status!=='added');const resolved=await spotifyUrisFast(spotifyTargets,button);const spotifyCache=new Map(JSON.parse(localStorage.getItem('recomendapp-track-uri-cache')||'[]'));let playlistId=data.playlist.spotify_id;
    const spotifyTracks=[];for(const track of spotifyTargets){const uri=spotifyCache.get(trackCacheKey(track));if(uri){spotifyTracks.push({...track,uri});await api.libraryUpdateTrack(track.id,{spotify_uri:uri,spotify_status:'found',last_error:null});}else if(spotifyCache.has(trackCacheKey(track)))await api.libraryUpdateTrack(track.id,{spotify_status:'missing'});}
    if(spotifyTracks.length){if(!playlistId){const created=await api.spotify('/me/playlists',{method:'POST',body:{name:data.playlist.name,public:false,description:'Sincronizada desde la biblioteca interna de Recomendapp.'}});playlistId=created.id;await api.libraryUpdatePlaylist(id,{spotify_id:playlistId});}message.textContent=`Guardando ${spotifyTracks.length} canciones en Spotify…`;const allAdded=data.tracks.filter(t=>t.spotify_status==='added'&&t.spotify_uri).map(t=>t.spotify_uri);const uris=[...new Set([...allAdded,...spotifyTracks.map(t=>t.uri)])];await api.spotify(`/playlists/${playlistId}/items`,{method:'PUT',body:{uris:uris.slice(0,100)}});for(let i=100;i<uris.length;i+=100)await api.spotify(`/playlists/${playlistId}/items`,{method:'POST',body:{uris:uris.slice(i,i+100)}});for(const track of spotifyTracks)await api.libraryUpdateTrack(track.id,{spotify_status:'added'});}
    const afterSpotify=await api.libraryGet(id),youtubeTargets=afterSpotify.tracks.filter(t=>t.spotify_status!=='added'&&t.youtube_status!=='added');if(youtubeTargets.length){message.textContent=`Buscando ${youtubeTargets.length} faltantes en YouTube…`;const yt=await youtubeFallback(youtubeTargets,button),youtubeCache=new Map(JSON.parse(localStorage.getItem('recomendapp-youtube-video-cache')||'[]'));let youtubeId=afterSpotify.playlist.youtube_id,youtubeUrl=afterSpotify.playlist.youtube_url;if(yt.trackIds.length&&!youtubeId){const created=await api.youtube('/playlists?part=snippet,status',{method:'POST',body:{snippet:{title:data.playlist.name,description:'Faltantes de Spotify guardados por Recomendapp.'},status:{privacyStatus:'private'}}});youtubeId=created.id;youtubeUrl=`https://www.youtube.com/playlist?list=${youtubeId}`;await api.libraryUpdatePlaylist(id,{youtube_id:youtubeId,youtube_url:youtubeUrl});}for(const track of youtubeTargets){const videoId=youtubeCache.get(trackCacheKey(track));if(!videoId)continue;await api.youtube('/playlistItems?part=snippet',{method:'POST',body:{snippet:{playlistId:youtubeId,resourceId:{kind:'youtube#video',videoId}}}});await api.libraryUpdateTrack(track.id,{youtube_video_id:videoId,youtube_status:'added',last_error:null});}if(yt.pending)message.textContent=`Sincronización parcial: ${yt.pending} canciones esperan la próxima cuota.`;}
    notify('Sincronización guardada');
  }catch(error){if(!/CANCELLED/.test(error.message)){message.textContent=`Pausada: ${error.message}`;notify('El progreso quedó guardado para reintentar');}}finally{button.disabled=false;api.setProcessActive(false);await showInternalPlaylist(id);}
}
async function showExternalPlaylist(provider,id){activeLibraryId=0;activeExternalPlaylist=`${provider}:${id}`;const item=externalLibraryPlaylists[provider].find(p=>p.id===id);renderLibrarySources(await api.libraryList(),0);libraryDetail.innerHTML=`<div class="external-loading"><strong>${escapeHtml(item?.name||'Playlist')}</strong><span>Leyendo canciones de ${provider==='spotify'?'Spotify':'YouTube'}…</span></div>`;try{let tracks=[];if(provider==='spotify'){tracks=await playlistItems(id);}else{let pageToken='';do{const data=await api.youtube(`/playlistItems?part=snippet,contentDetails&playlistId=${encodeURIComponent(id)}&maxResults=50${pageToken?`&pageToken=${encodeURIComponent(pageToken)}`:''}`);tracks.push(...(data.items||[]).map(row=>({name:row.snippet?.title||'Video no disponible',artist:row.snippet?.videoOwnerChannelTitle||row.snippet?.channelTitle||'YouTube',videoId:row.contentDetails?.videoId||row.snippet?.resourceId?.videoId})));pageToken=data.nextPageToken||'';}while(pageToken)}const platform=provider==='spotify'?'Spotify':'YouTube';libraryDetail.innerHTML=`<div class="library-detail-head">${item?.image?`<img class="library-cover" src="${escapeHtml(item.image)}" alt="">`:'<div class="library-cover placeholder">♫</div>'}<div><i class="platform-tag ${provider}">${platform}</i><h2>${escapeHtml(item?.name||'Playlist')}</h2><p>${tracks.length.toLocaleString()} ${provider==='spotify'?'canciones':'videos'}</p></div></div><div class="library-sync-message">Selecciona el nombre de una canción para abrirla en ${platform}.</div><div class="library-tracks">${tracks.map((track,index)=>{const url=provider==='spotify'?spotifyTrackUrl(track):`https://www.youtube.com/watch?v=${encodeURIComponent(track.videoId||'')}`;return `<div class="library-track"><span>${index+1}</span><div><strong><a class="song-link" href="${url}" target="_blank">${escapeHtml(track.name)}</a></strong><small>${escapeHtml(track.artist)}</small></div><i class="platform-tag ${provider}">${platform}</i></div>`}).join('')||'<div class="neighbors-status">Esta playlist no contiene canciones disponibles.</div>'}</div>`;}catch(error){libraryDetail.innerHTML=`<div class="neighbors-status">No se pudo leer esta playlist: ${escapeHtml(error.message)}</div>`;}}
libraryPlaylists.addEventListener('click',event=>{const card=event.target.closest('[data-library-id]');if(card){activeExternalPlaylist='';showInternalPlaylist(card.dataset.libraryId);return}const external=event.target.closest('[data-external-provider]');if(external)showExternalPlaylist(external.dataset.externalProvider,external.dataset.externalId);});
libraryDetail.addEventListener('click',async event=>{if(event.target.closest('[data-library-sync]'))await syncInternalPlaylist(activeLibraryId);if(event.target.closest('[data-library-retry]')){await api.libraryRetry(activeLibraryId);await syncInternalPlaylist(activeLibraryId);}});
libraryDetail.addEventListener('change',async event=>{if(!event.target.matches('[data-library-cover]'))return;const file=event.target.files?.[0];if(!file)return;try{const image=await createImageBitmap(file),canvas=document.createElement('canvas');canvas.width=canvas.height=300;const context=canvas.getContext('2d'),side=Math.min(image.width,image.height);context.drawImage(image,(image.width-side)/2,(image.height-side)/2,side,side,0,0,300,300);const cover=canvas.toDataURL('image/jpeg',.82),data=await api.libraryGet(activeLibraryId);await api.libraryUpdatePlaylist(activeLibraryId,{cover_image:cover});if(data.playlist.spotify_id)await api.spotifyUploadCover(data.playlist.spotify_id,cover);notify('Imagen de playlist actualizada');await showInternalPlaylist(activeLibraryId);}catch(error){if(/scope|permission|403/i.test(error.message))notify('Reconecta Spotify para autorizar el cambio de portada');else notify(error.message)}});
document.querySelector('#windowMinimize').addEventListener('click',()=>api.minimize());document.querySelector('#windowMaximize').addEventListener('click',()=>api.maximize());document.querySelector('#windowClose').addEventListener('click',()=>api.close());
render();
